object/public/perfumissimo_bucket/settings/home/carousel/1774737617237_2_Perfume_Bottle_Video_Z50W1XPP-d354b447.mp4\"},{\"headline\":\"Hasta 20% OFF por tiempo limitado\",\"subhead\":\"Aprovecha ofertas activas antes de que terminen.\",\"ctaText\":\"Aprovechar oferta\",\"ctaLink\":\"/promotion\",\"mediaType\":\"video\",\"mediaUrl\":\"https://zivdglmfkvlmylbspjqs.supabase.co/storage/v1/object/public/perfumissimo_bucket/settings/home/carousel/1774738770305_3_Perfume_Bottle_Video_sfca9r9l-cb67c0e0.mp4\"}]','[{\"title\":\"Para El\",\"subtitle\":\"Fresco. Intenso. Memorables.\",\"emotion\":\"Define tu presencia\",\"link\":\"/catalog?category=hombre\",\"mediaType\":\"video\",\"mediaUrl\":\"https://zivdglmfkvlmylbspjqs.supabase.co/storage/v1/object/public/perfumissimo_bucket/settings/home/categories/1774742176581_1_Luxury_Men_s_Perfume_Product_Video-64e6bb82.mp4\"},{\"title\":\"Para Ella\",\"subtitle\":\"Elegancia que se siente cerca.\",\"emotion\":\"Elegancia femenina\",\"link\":\"/catalog?category=mujer\",\"mediaType\":\"video\",\"mediaUrl\":\"https://zivdglmfkvlmylbspjqs.supabase.co/storage/v1/object/public/perfumissimo_bucket/settings/home/categories/1774742182433_2_Silent_Perfume_Product_Video_Generation-7de58352.mp4\"},{\"title\":\"Exclusivos / Nicho\",\"subtitle\":\"Oud, arabes, raros.\",\"emotion\":\"Fragancias unicas\",\"link\":\"/catalog?category=arabe\",\"mediaType\":\"video\",\"mediaUrl\":\"https://zivdglmfkvlmylbspjqs.supabase.co/storage/v1/object/public/perfumissimo_bucket/settings/home/categories/1774745107001_3_Luxury_Perfume_Product_Video_Generation-053e63bc.mp4\"},{\"title\":\"Ofertas\",\"subtitle\":\"Descuentos activos hoy.\",\"emotion\":\"Compra inteligente\",\"link\":\"/catalog?promo=true\",\"mediaType\":\"image\",\"mediaUrl\":\"\"}]',0.00,'Perfumero de lujo (5ml)',NULL,4);
